/**
 * 写卡 Agent 引擎
 *
 * 一个「对话式 + 多步骤工作流」的角色卡创作 agent：
 * - 对话式（层次 B）：用户用自然语言描述需求，agent 会先反问澄清关键设定，多轮对话推进。
 * - 多步骤工作流（层次 A）：内部把写卡拆成 澄清 → 大纲 → 完整角色卡 → 配套产物（开场白/世界书）几个阶段，
 *   每个阶段都是一次独立的 AI 调用，阶段产物对用户可见、可打回重做。
 *
 * 设计要点：
 * - 不依赖模型的 function-calling 能力（公益站模型参差不齐），用「固定阶段 + 结构化输出」来编排，稳。
 * - 复用现有 requestToolsAiText（自动兼容直连 API / 酒馆 API / 流式）。
 * - 每次 AI 调用都带重试思路由调用方决定（这里失败直接抛，UI 负责提示）。
 */

import {
    extractJsonFromText,
    requestToolsAiText,
    type ToolsAiSettings
} from '../components/tools/toolsAiService';

/** agent 的工作阶段 */
export type AgentStage = 'clarify' | 'outline' | 'card' | 'extras' | 'done';

/** 对话消息 */
export interface AgentMessage {
  role: 'user' | 'assistant';
  content: string;
  /** 可选：该条消息携带的结构化产物（大纲/角色卡等），供 UI 渲染操作按钮 */
  artifact?: AgentArtifact;
}

export interface AgentArtifact {
  type: 'outline' | 'card' | 'extras';
  /** 给用户看的正文（markdown / yaml 文本） */
  text: string;
  /** 结构化数据（extras 阶段才有：greeting / worldbook 候选等） */
  data?: any;
}

export interface AgentState {
  stage: AgentStage;
  messages: AgentMessage[];
  /** 已确认的设定要点（澄清阶段逐步累积） */
  facts: string[];
  /** 最近一次大纲文本 */
  outline?: string;
  /** 最近一次完整角色卡（YAML） */
  card?: string;
  /** 参考的已有角色卡内容（可多张）：AI 会参考它们的写法/风格/详略，但产出全新角色 */
  referenceCards?: { name: string; text: string }[];
}

const MODEL_FALLBACK = 'gpt-4o-mini';

function buildPayload(settings: ToolsAiSettings, messages: { role: string; content: string }[]) {
  return {
    model: (settings as any).model || MODEL_FALLBACK,
    messages,
    temperature: (settings as any).temperature ?? 0.8,
    // 写卡 agent 输出较长（完整角色卡 + 配套产物），默认拉满到 65535，避免被截断
    max_tokens: 65535,
  };
}

const SYSTEM_BASE = `你是「猫猫写卡助手」，一位专业、热情的 SillyTavern 角色卡创作 agent。
你会通过多轮对话帮用户从零创作一张高质量角色卡。全程使用中文。
风格：自然、有想法、会主动给建议，不机械地填表。`;

/** 把参考卡拼成提示词片段（无参考则返回空串） */
function refSnippet(state: AgentState): string {
  const refs = state.referenceCards;
  if (!refs || refs.length === 0) return '';
  const body = refs
    .map((r, i) => `【参考${i + 1}·${r.name || '未命名'}】\n${r.text}`)
    .join('\n\n');
  return `\n\n以下是${refs.length}张参考角色卡（仅供参考其写法、风格、详略和字段组织，可综合借鉴，但不要照抄设定，要产出全新角色）：\n${body}`;
}

/**
 * 阶段一·澄清：根据用户已给的信息，判断是否需要追问。
 * 返回 JSON：{ "ready": boolean, "reply": string, "facts": string[] }
 * - ready=false 时 reply 是「友好的追问」（一次问 2-4 个关键问题，不要一次问太多）。
 * - ready=true 时表示信息够了，reply 是「确认要点并告知即将生成大纲」。
 * - facts 是从本轮对话中提炼出的、已确定的设定要点（累积用）。
 */
export async function agentClarify(
  state: AgentState,
  userInput: string,
  settings: ToolsAiSettings,
): Promise<{ ready: boolean; reply: string; facts: string[] }> {
  const history = state.messages
    .map(m => `${m.role === 'user' ? '用户' : '助手'}：${m.content}`)
    .join('\n');

  const sys = `${SYSTEM_BASE}

当前阶段：需求澄清。
已确认要点：${state.facts.length ? state.facts.join('；') : '（暂无）'}

任务：判断现有信息是否足够开始设计角色（至少要有：角色定位/性格倾向、与用户的关系或场景、大致背景三者中的多数）。
- 如果还不够，提出 2-4 个最关键的追问，语气自然友好。
- 如果已经足够，明确告诉用户「信息够了，这就为你梳理人物大纲」。
${state.referenceCards?.length ? '- 用户提供了参考卡，可参考它们涉及的设定维度来设计追问，但产出的是全新角色。' : ''}
只输出 JSON，不要 markdown、不要解释：
{"ready": true/false, "reply": "给用户看的话", "facts": ["从对话中确认的设定要点", "..."]}${refSnippet(state)}`;

  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: `历史对话：\n${history}\n\n用户最新输入：${userInput}` },
  ];

  const raw = await requestToolsAiText({ requestPayload: buildPayload(settings, messages), settings });
  const parsed = extractJsonFromText(raw);
  if (parsed?.json && typeof parsed.json.reply === 'string') {
    return {
      ready: !!parsed.json.ready,
      reply: parsed.json.reply,
      facts: Array.isArray(parsed.json.facts) ? parsed.json.facts.map(String) : [],
    };
  }
  // 解析失败：把原文当作追问回复，保持对话不中断
  return { ready: false, reply: raw.trim(), facts: [] };
}

/**
 * 阶段二·大纲：基于已确认要点产出「人物大纲」（给用户确认，不是最终卡）。
 */
export async function agentOutline(state: AgentState, settings: ToolsAiSettings): Promise<string> {
  const sys = `${SYSTEM_BASE}

当前阶段：人物大纲。
基于已确认要点，写一份简洁的人物大纲（markdown），包含：
1. 一句话定位
2. 外貌速写
3. 性格（3-5 个关键特质，附简短说明）
4. 背景/经历要点
5. 与用户的关系或初始场景
6. 说话风格

不要写成最终角色卡，这是给用户快速确认方向用的。控制在 400 字以内。${refSnippet(state)}`;

  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: `已确认要点：\n${state.facts.join('\n')}` },
  ];
  return (await requestToolsAiText({ requestPayload: buildPayload(settings, messages), settings })).trim();
}

/**
 * 阶段三·完整角色卡：基于（已确认的）大纲产出完整 YAML 角色卡。
 */
export async function agentCard(state: AgentState, settings: ToolsAiSettings): Promise<string> {
  const sys = `${SYSTEM_BASE}

当前阶段：生成完整角色卡。
基于人物大纲，产出一张完整、立体的 YAML 格式角色卡（纯中文），字段至少包含：
name、外貌、性格、背景、说话风格、喜好与厌恶、与用户的关系、行为示例。
要求有血有肉、细节可信，避免空洞套话。只输出 YAML，不要额外解释、不要 markdown 代码块标记。`;

  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: `人物大纲：\n${state.outline || state.facts.join('\n')}` },
  ];
  return (await requestToolsAiText({ requestPayload: buildPayload(settings, messages), settings })).trim();
}

export interface AgentExtras {
  greeting: string;
  worldbook: { title: string; content: string; keys: string[] }[];
}

/**
 * 阶段四·配套产物：基于完整角色卡，产出开场白 + 世界书候选条目。
 * 返回结构化数据，UI 可一键写入。
 */
export async function agentExtras(state: AgentState, settings: ToolsAiSettings): Promise<AgentExtras> {
  const sys = `${SYSTEM_BASE}

当前阶段：生成配套产物。
基于完整角色卡，产出：
1. 一段沉浸式开场白（第一条消息，150-300 字，有场景有动作有对话）。
2. 2-4 条世界书条目（角色相关的设定/背景/关系，适合长期记忆）。

只输出 JSON，不要 markdown、不要解释：
{"greeting": "开场白文本", "worldbook": [{"title": "条目标题", "content": "条目内容", "keys": ["触发关键词"]}]}`;

  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: `完整角色卡：\n${state.card || ''}` },
  ];
  const raw = await requestToolsAiText({ requestPayload: buildPayload(settings, messages), settings });
  const parsed = extractJsonFromText(raw);
  const data = parsed?.json || {};
  return {
    greeting: typeof data.greeting === 'string' ? data.greeting : '',
    worldbook: Array.isArray(data.worldbook)
      ? data.worldbook
          .filter((w: any) => w && (w.title || w.content))
          .map((w: any) => ({
            title: String(w.title || '未命名条目'),
            content: String(w.content || ''),
            keys: Array.isArray(w.keys) ? w.keys.map(String) : [],
          }))
      : [],
  };
}

/** 新建一个空白 agent 状态 */
export function createAgentState(): AgentState {
  return { stage: 'clarify', messages: [], facts: [] };
}

/**
 * 流式生成完整角色卡：边生成边通过 onChunk 回调累计文本，UI 可做打字机效果。
 */
export async function agentCardStream(
  state: AgentState,
  settings: ToolsAiSettings,
  onChunk: (fullText: string) => void,
): Promise<string> {
  const sys = `${SYSTEM_BASE}

当前阶段：生成完整角色卡。
基于人物大纲，产出一张完整、立体的 YAML 格式角色卡（纯中文），字段至少包含：
name、外貌、性格、背景、说话风格、喜好与厌恶、与用户的关系、行为示例。
要求有血有肉、细节可信，避免空洞套话。只输出 YAML，不要额外解释、不要 markdown 代码块标记。${refSnippet(state)}`;

  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: `人物大纲：\n${state.outline || state.facts.join('\n')}` },
  ];
  return (await streamToolsAiText(buildPayload(settings, messages), settings, onChunk)).trim();
}

/**
 * 针对完整角色卡的「某个方面」做局部微调，保留其余内容不变。
 * 例如：让性格更毒舌、把背景改成现代都市、丰富外貌描写等。
 */
export async function agentTweakCard(
  card: string,
  tweakRequest: string,
  settings: ToolsAiSettings,
  onChunk?: (fullText: string) => void,
): Promise<string> {
  const sys = `${SYSTEM_BASE}

当前任务：对现有角色卡做局部微调。
原则：
- 只按用户指出的方面调整，其余内容尽量原样保留，不要整卡重写。
- 输出调整后的【完整】YAML 角色卡（纯中文），只输出 YAML，不要解释、不要代码块标记。`;

  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: `现有角色卡：\n${card}\n\n要微调的方面：\n${tweakRequest}` },
  ];
  if (onChunk) {
    return (await streamToolsAiText(buildPayload(settings, messages), settings, onChunk)).trim();
  }
  return (await requestToolsAiText({ requestPayload: buildPayload(settings, messages), settings })).trim();
}

// ===== 会话草稿持久化 =====
// 按「角色 avatar」隔离保存，刷新/切角色后能接着上次的对话，避免生成到一半全丢。

function getAgentDraftKey(): string {
  let who = 'default';
  try {
    const TH = (window as any).TavernHelper;
    const char = TH?.getCharData?.('current');
    who = char?.avatar || char?.name || 'default';
  } catch {
    /* ignore */
  }
  return `maomaomz_card_agent_draft_${who}`;
}

/** 保存当前会话草稿（含模式） */
export function saveAgentDraft(state: AgentState, mode: string): void {
  try {
    localStorage.setItem(getAgentDraftKey(), JSON.stringify({ state, mode, savedAt: Date.now() }));
  } catch (e) {
    console.warn('保存写卡会话草稿失败（忽略）:', e);
  }
}

/** 读取会话草稿；无则返回 null */
export function loadAgentDraft(): { state: AgentState; mode: string } | null {
  try {
    const raw = localStorage.getItem(getAgentDraftKey());
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (parsed?.state && Array.isArray(parsed.state.messages)) {
      return { state: parsed.state as AgentState, mode: parsed.mode || 'create' };
    }
  } catch (e) {
    console.warn('读取写卡会话草稿失败（忽略）:', e);
  }
  return null;
}

/** 清除会话草稿 */
export function clearAgentDraft(): void {
  try {
    localStorage.removeItem(getAgentDraftKey());
  } catch {
    /* ignore */
  }
}

/** 读取当前酒馆角色卡的主要字段，拼成可读文本（供 agent 改写/续写用） */
export function readCurrentCharacterCard(): string {
  try {
    const TH = (window as any).TavernHelper;
    const char = TH?.getCharData?.('current');
    return charToText(char);
  } catch (e) {
    console.warn('读取当前角色卡失败:', e);
    return '';
  }
}

/** 把角色卡对象拼成可读文本 */
function charToText(char: any): string {
  if (!char) return '';
  const parts: string[] = [];
  if (char.name) parts.push(`名称：${char.name}`);
  const desc = char.description || char.data?.description;
  if (desc) parts.push(`描述：${desc}`);
  const persona = char.personality || char.data?.personality;
  if (persona) parts.push(`性格：${persona}`);
  const scenario = char.scenario || char.data?.scenario;
  if (scenario) parts.push(`场景：${scenario}`);
  const mes = char.first_mes || char.data?.first_mes;
  if (mes) parts.push(`开场白：${mes}`);
  const examples = char.mes_example || char.data?.mes_example;
  if (examples) parts.push(`对话示例：${examples}`);
  return parts.join('\n\n');
}

export interface CharacterListItem {
  avatar: string;
  name: string;
}

/** 列出酒馆里全部角色（用于「参考某张卡」的选择列表） */
export function listAllCharacters(): CharacterListItem[] {
  try {
    const st: any = typeof SillyTavern !== 'undefined' ? SillyTavern : (window as any).SillyTavern;
    const ctx = typeof st?.getContext === 'function' ? st.getContext() : st;
    const chars = ctx?.characters || st?.characters || [];
    return (chars as any[])
      .filter(c => c && c.avatar)
      .map(c => ({ avatar: String(c.avatar), name: String(c.name || c.avatar) }));
  } catch (e) {
    console.warn('获取角色列表失败:', e);
    return [];
  }
}

/** 按 avatar 读取指定角色卡的可读文本（用于参考） */
export function readCharacterCardByAvatar(avatar: string): string {
  try {
    const st: any = typeof SillyTavern !== 'undefined' ? SillyTavern : (window as any).SillyTavern;
    const ctx = typeof st?.getContext === 'function' ? st.getContext() : st;
    const chars = ctx?.characters || st?.characters || [];
    const char = (chars as any[]).find(c => c && c.avatar === avatar);
    return charToText(char);
  } catch (e) {
    console.warn('按 avatar 读取角色卡失败:', e);
    return '';
  }
}

/**
 * 改写/续写模式：基于「现有角色卡」+「用户的改写需求」产出新的完整角色卡（YAML）。
 * 与从零创作不同，这里要尽量保留原卡的设定基调，只按需求调整。
 */
export async function agentRewriteCard(
  existingCard: string,
  requirement: string,
  settings: ToolsAiSettings,
): Promise<string> {
  const sys = `${SYSTEM_BASE}

当前任务：在现有角色卡基础上按用户需求改写/扩写。
原则：
- 保留原卡的核心设定与基调，只按需求调整或补充，不要凭空推翻。
- 输出完整的 YAML 格式角色卡（纯中文），字段尽量齐全、有血有肉。
- 只输出 YAML，不要额外解释、不要 markdown 代码块标记。`;

  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: `现有角色卡：\n${existingCard}\n\n改写需求：\n${requirement}` },
  ];
  return (await requestToolsAiText({ requestPayload: buildPayload(settings, messages), settings })).trim();
}

export type CharField = 'description' | 'personality' | 'scenario' | 'first_mes' | 'mes_example';

/** 读取当前角色某个字段的现值（用于插入前备份） */
export function readCurrentCharacterField(field: CharField): string {
  try {
    const TH = (window as any).TavernHelper;
    const char = TH?.getCharData?.('current');
    if (char) {
      const v = char[field] ?? char.data?.[field];
      if (typeof v === 'string') return v;
    }
    const st: any = (window as any).SillyTavern || (window as any).parent?.SillyTavern;
    const ctx = typeof st?.getContext === 'function' ? st.getContext() : st;
    const charId = ctx?.characterId ?? st?.characterId;
    const c = ctx?.characters?.[charId] || st?.characters?.[charId];
    const v = c?.[field] ?? c?.data?.[field];
    return typeof v === 'string' ? v : '';
  } catch {
    return '';
  }
}

export interface InsertResult {
  ok: boolean;
  /** 该字段插入前的旧值，用于撤销 */
  backup: string;
  field: CharField;
}

/**
 * 把一张完整角色卡（YAML 或纯文本）插入到当前酒馆角色的指定字段。
 * 插入前会先读出旧值作为备份，返回的 backup 可传给 restoreCharacterField 撤销。
 */
export async function insertCardToCharacter(card: string, field: CharField = 'description'): Promise<InsertResult> {
  const backup = readCurrentCharacterField(field);
  const ok = await writeCharacterField(field, card);
  return { ok, backup, field };
}

/** 撤销：把某字段恢复成备份的旧值 */
export async function restoreCharacterField(field: CharField, backup: string): Promise<boolean> {
  return writeCharacterField(field, backup);
}

/** 实际写入角色字段（内部用） */
async function writeCharacterField(field: CharField, value: string): Promise<boolean> {
  const TH = (window as any).TavernHelper;
  const st = (window as any).SillyTavern || (window as any).parent?.SillyTavern;
  try {
    if (TH?.setCharData) {
      await TH.setCharData('current', { [field]: value });
      return true;
    }
    if (st?.getContext) {
      const ctx = st.getContext();
      const charId = ctx.characterId ?? ctx.characters?.findIndex?.((c: any) => c.avatar === ctx.character?.avatar);
      if (charId === undefined || charId < 0) throw new Error('未找到当前角色');
      const res = await fetch('/api/characters/edit', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...(typeof st.getRequestHeaders === 'function' ? st.getRequestHeaders() : {}),
        },
        body: JSON.stringify({ avatar_url: ctx.characters?.[charId]?.avatar, [field]: value }),
      });
      return res.ok;
    }
  } catch (e) {
    console.warn('写入角色字段失败:', e);
  }
  return false;
}
